//
import { splat } from '../../../utils/zcutils';
import { translateString } from '../../../utils/svg-transforms';
import { getSVGsymbol } from '../../../utils/svg-symbols';
import { getMarkValue } from '../../parser/parser-helpers';

function pointMark(config, cache) {
    return {
        config: {
            d: function(d, i) {
                let node = this,
                    args = [d, i],
                    _shape,
                    _size;

                if (config.d) {
                    ({ shape: _shape, size: _size } = getMarkValue(node, args, config, 'd', cache)); // TODO: default value
                } else {
                    _shape = getMarkValue(node, args, config, 'shape', cache);
                    _size = getMarkValue(node, args, config, 'size', cache);
                }

                return getSVGsymbol(_shape)(...splat(_size));
            },
            transform: function(d, i) {
                let node = this,
                    args = [d, i],
                    _x,
                    _y,
                    _angle;

                if (config.transform) {
                    ({ x: _x, y: _y, angle: _angle } = getMarkValue(node, args, config, 'transform', cache));
                } else {
                    _x = getMarkValue(node, args, config, 'x', cache);
                    _y = getMarkValue(node, args, config, 'y', cache);
                    _angle = getMarkValue(node, args, config, 'angle', cache);
                }

                return translateString([_x, _y], _angle);
            }
        },
        depends: {
            d: ['shape', 'size'],
            transform: ['x', 'y', 'angle']
        }
    };
}

export { pointMark };
